def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 2, -1):
                for b in range(1, a + 5):
                    for c in range(1, b + 3):
                        factor = ((ratio - a) ** 7) / ((a * b * c) + 1.5)
                        priority += factor * np.tan(ratio * c / (a + 2)) * np.sin(b * ratio)
            priority += (np.exp(ratio - 8) * np.sin(ratio * 1.3)) ** 2
            if bin_cap < item * 0.4:
                priority += np.log1p(item ** 3 * bin_cap) * 7
            elif bin_cap > item * 3:
                priority -= np.exp(-4 * ratio) * 6
        elif 5 < ratio <= 8:
            for p in range(1, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 4):
                    val = ((ratio - p) ** 4) * np.cos(ratio * p * 1.1) / (q + 1.0)
                    priority += np.tanh(val) * 1.5
            priority += np.log(ratio) * 12 - np.tanh(ratio - 5) * 2.5
            for idx_offset in range(1, 6):
                if (i + idx_offset) % 5 == 0:
                    priority += np.sin(ratio * (i + idx_offset) * 1.3) * 0.5
                else:
                    priority -= np.cos(ratio * (i + idx_offset) * 1.2) * 0.4
        elif 2 <= ratio <= 5:
            s = 0
            for r in range(1, 20):
                s += ((ratio - 2) ** r) / (r * 2.5) * np.cos(r * ratio * 0.9)
            priority = (s * np.cos(10 * ratio)) - np.log(ratio) * 8 + np.tanh(5 * (5 - ratio)) * 3
            if bin_cap < item * 0.7:
                priority += np.sqrt(item / (bin_cap + 0.1)) * 5
            else:
                priority -= np.exp(-0.5 * ratio) * 2
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 15):
                s += ((2 - ratio) ** n) / (n ** 2 + 1.2)
            if bin_cap < item * 1.15:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 4.5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-1.2 / (ratio + 0.1))
            for m in range(1, 8):
                priority += np.sin(m * ratio * i * 1.2) * ((ratio - 1) ** m) / (m * 0.95)
            for w in range(5):
                priority += np.cos(i * ratio * (w + 1)) * 0.4
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 25):
                s += ((1 - ratio) ** n) / (n * 3.5)
            priority = s
            if (i + int(item * 1.7)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 2.5) + 1.5)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.5) * 0.8
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 4.5
            else:
                priority -= np.exp(-ratio * 0.8) * 2.5
        elif 0.15 <= ratio < 0.5:
            s = 0
            for k in range(1, 20):
                s += ((0.5 - ratio) ** k) / (k * 2.8) * np.cos(k * ratio * 1.5)
            priority = s + 1.0 / (bin_cap + 5)
            if int(item * 1.5) % 6 == 0:
                priority *= 3
            else:
                priority /= 3.2
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.5) * 3.5
            for m in range(1, 10):
                priority += ((0.5 - ratio) ** m) / (m * 5) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 15):
                s += ((0.15 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.8) % 7 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.07:
                priority += np.log1p(item * bin_cap) * 7.5
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 12):
                priority += ((0.15 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.7)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6.5
        elif bin_cap > item * 3.5:
            priority -= np.exp(-4 * ratio) * 5.5
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.5) * 0.45
            else:
                priority -= np.cos(ratio * (i + idx) * 1.4) * 0.35
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.4) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
